extern "C" jayess_value *jayess_webview_bind(jayess_value *view_value, jayess_value *name_value) {
    jayess_webview_state *state = jayess_webview_expect_state(view_value, "jayess_webview_bind");
    const char *name = jayess_expect_string(name_value, "jayess_webview_bind");
    jayess_webview_binding *binding = nullptr;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (jayess_webview_find_binding(state, name) != nullptr) {
        jayess_throw_named_error("WebviewError", "webview binding already exists");
        return jayess_value_undefined();
    }
    binding = (jayess_webview_binding *)calloc(1, sizeof(jayess_webview_binding));
    if (binding == nullptr) {
        jayess_throw_error("failed to allocate webview binding");
        return jayess_value_undefined();
    }
    binding->state = state;
    binding->name = jayess_webview_dup(name);
    if (binding->name == nullptr) {
        free(binding);
        jayess_throw_error("failed to copy webview binding name");
        return jayess_value_undefined();
    }
    if (jayess_webview_throw_if_error(webview_bind(state->view, binding->name, jayess_webview_binding_cb, binding), "webview_bind failed")) {
        free(binding->name);
        free(binding);
        return jayess_value_undefined();
    }
    binding->next = state->bindings;
    state->bindings = binding;
    return jayess_value_from_bool(1);
}

extern "C" jayess_value *jayess_webview_unbind(jayess_value *view_value, jayess_value *name_value) {
    jayess_webview_state *state = jayess_webview_expect_state(view_value, "jayess_webview_unbind");
    const char *name = jayess_expect_string(name_value, "jayess_webview_unbind");
    jayess_webview_binding *binding = nullptr;
    jayess_webview_binding *previous = nullptr;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    binding = state->bindings;
    while (binding != nullptr) {
        if (strcmp(binding->name, name) == 0) {
            break;
        }
        previous = binding;
        binding = binding->next;
    }
    if (binding == nullptr) {
        jayess_throw_named_error("WebviewError", "webview binding was not found");
        return jayess_value_undefined();
    }
    if (jayess_webview_throw_if_error(webview_unbind(state->view, name), "webview_unbind failed")) {
        return jayess_value_undefined();
    }
    if (previous != nullptr) {
        previous->next = binding->next;
    } else {
        state->bindings = binding->next;
    }
    binding->next = nullptr;
    jayess_webview_free_bindings(binding);
    return jayess_value_from_bool(1);
}

extern "C" jayess_value *jayess_webview_next_binding_event(jayess_value *view_value) {
    jayess_webview_state *state = jayess_webview_expect_state(view_value, "jayess_webview_next_binding_event");
    jayess_webview_binding_event *event = nullptr;
    jayess_object *result = nullptr;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    event = state->event_head;
    if (event == nullptr) {
        return jayess_value_undefined();
    }
    state->event_head = event->next;
    if (state->event_head == nullptr) {
        state->event_tail = nullptr;
    }
    result = jayess_object_new();
    jayess_object_set_value(result, "name", jayess_value_from_string(event->name != nullptr ? event->name : ""));
    jayess_object_set_value(result, "id", jayess_value_from_string(event->id != nullptr ? event->id : ""));
    jayess_object_set_value(result, "request", jayess_value_from_string(event->request != nullptr ? event->request : ""));
    jayess_webview_free_event(event);
    return jayess_value_from_object(result);
}

extern "C" jayess_value *jayess_webview_return_binding(jayess_value *view_value, jayess_value *id_value, jayess_value *status_value, jayess_value *result_value) {
    jayess_webview_state *state = jayess_webview_expect_state(view_value, "jayess_webview_return_binding");
    const char *id = jayess_expect_string(id_value, "jayess_webview_return_binding");
    int status = (int)jayess_value_to_number(status_value);
    const char *result = nullptr;
    char *result_copy = nullptr;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_value_is_nullish(result_value)) {
        result = jayess_value_as_string(result_value);
        if (result == nullptr) {
            result_copy = jayess_value_to_string_copy(result_value);
            if (jayess_has_exception()) {
                return jayess_value_undefined();
            }
            result = result_copy;
        }
    } else {
        result = "";
    }
    if (jayess_webview_throw_if_error(webview_return(state->view, id, status, result), "webview_return failed")) {
        free(result_copy);
        return jayess_value_undefined();
    }
    free(result_copy);
    return jayess_value_from_bool(1);
}

